def make_dcgan_generator_block(in_ch, out_ch, first=False):
    """Single upsampling block. `first` = 4x4 from 1x1 (nz input)."""
    if first:
        return nn.Sequential(
            nn.ConvTranspose2d(in_ch, out_ch, 4, 1, 0, bias=False),
            nn.BatchNorm2d(out_ch),
            nn.ReLU(True),
        )
    return nn.Sequential(
        nn.ConvTranspose2d(in_ch, out_ch, 4, 2, 1, bias=False),
        nn.BatchNorm2d(out_ch),
        nn.ReLU(True),
    )

# Build a 128x128 generator dynamically
# z -> 4 -> 8 -> 16 -> 32 -> 64 -> 128
def build_generator(nz=100, ngf=64, nc=3, num_upsample=5):
    channels = [nz] + [ngf * 2**(num_upsample - 1 - i) for i in range(num_upsample)]
    layers = [make_dcgan_generator_block(channels[0], channels[1], first=True)]
    for i in range(1, num_upsample):
        layers.append(make_dcgan_generator_block(channels[i], channels[i+1]))
    layers.append(nn.Sequential(
        nn.ConvTranspose2d(channels[-1], nc, 4, 2, 1, bias=False),
        nn.Tanh(),
    ))
    return nn.Sequential(*layers)

def make_upsample_conv_block(in_ch, out_ch):
    """Artefact-free alternative to ConvTranspose2d."""
    return nn.Sequential(
        nn.Upsample(scale_factor=2, mode='nearest'),
        nn.Conv2d(in_ch, out_ch, kernel_size=3, stride=1, padding=1, bias=False),
        nn.BatchNorm2d(out_ch),
        nn.ReLU(True),
    )

class ConditionalDCGANGenerator(nn.Module):
    def __init__(self, nz=100, ngf=64, nc=3, num_classes=10, embed_dim=50):
        super().__init__()
        self.label_emb = nn.Embedding(num_classes, embed_dim)
        self.main = DCGANGenerator(nz + embed_dim, ngf, nc)  # reuse backbone

    def forward(self, z, labels):
        # Concatenate noise and label embedding along channel dim
        e = self.label_emb(labels)                 # (B, embed_dim)
        z_cond = torch.cat([z.squeeze(), e], dim=1)  # (B, nz+embed_dim)
        z_cond = z_cond.unsqueeze(-1).unsqueeze(-1)   # (B, nz+embed_dim, 1, 1)
        return self.main(z_cond)


class ConditionalDCGANDiscriminator(nn.Module):
    def __init__(self, ndf=64, nc=3, num_classes=10, img_size=64):
        super().__init__()
        self.label_emb = nn.Embedding(num_classes, img_size * img_size)
        self.img_size = img_size
        # nc+1 because we tile one label channel alongside the image
        self.main = DCGANDiscriminator(ndf, nc + 1)

    def forward(self, x, labels):
        B, C, H, W = x.shape
        e = self.label_emb(labels).view(B, 1, H, W)  # (B, 1, H, W)
        x_cond = torch.cat([x, e], dim=1)             # (B, nc+1, H, W)
        return self.main(x_cond)

def weights_init_ortho(m):
    classname = m.__class__.__name__
    if classname.find('Conv') != -1:
        nn.init.orthogonal_(m.weight.data)
    elif classname.find('BatchNorm') != -1:
        nn.init.normal_(m.weight.data, 1.0, 0.02)
        nn.init.constant_(m.bias.data, 0)
